var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"도착했습니다, 여러분!","JPN":"着きました、みなさん！","ENG":"We're back, gentlemen!","TWN":"到了，各位！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"현실세계라고요! 이제 우리 모두 고생 끝, 행복 시작입니다!","JPN":"現実世界です！　もうこれで苦労は終わり、明るい未来が待っているのです！","ENG":"We're back in the Normalside! It's nothing but green pastures for us from here on out!","TWN":"是現實世界！我們終於苦盡甘來了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"분위기가 이게 뭡니까, 다들? 갑자기 안 하던 다이브 멀미라도 시작했어요?","JPN":"この雰囲気はなんなんですか。急にダイブ酔いでも流行りだしたんですか？","ENG":"Come on, why the long face, everyone? Did you get Dive sickness or something?","TWN":"大家這是怎麼了？突然開始躍入眩暈了？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"이보세요. 고용주 양반.","JPN":"なあ、雇い主さんよ。","ENG":"Listen... Boss man.","TWN":"我說，雇主。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"역시 지금이라도 돌아갑시다. 대장이 못 탄 게 마음에 걸려.","JPN":"やはり戻ったほうがいいのでは。隊長を乗せられなかったのが気になる。","ENG":"Let's go back. It's not too late. I still feel guilty about leaving the Captain behind.","TWN":"還是回去吧。隊長沒有搭上船，我心裡有些擔心。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"하아...... 이 인간들 참 누가 가르쳤는지 줏대가 없구만......","JPN":"はあ……みなさん、何もわかってないのですね。","ENG":"*Sigh* Grow a spine already...","TWN":"哈啊……你們這群人，也不知道誰教得如此沒有骨氣……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"언제 고장날지도 모르는 고물 배를 타고 생지옥으로 다시 기어들어가자고요?","JPN":"いつ壊れるかしらないポンコツ艦船に乗って、またあの生き地獄に戻るってことですか？","ENG":"You want to drag this old junk of a ship back to hell? After barely getting it off the ground?","TWN":"你現在是讓我再坐上隨時可能出故障的破船，再爬回地獄？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"아니, 막말로 다시 간다고 해 보죠. 그래서 댁들이 뭘 할 수 있는데요?","JPN":"で、戻ったとしてあなたたちに何ができると思いますか？","ENG":"Fine, let's assume we're crazy enough to do that. What exactly will you do back down there?","TWN":"不是，就算回去了。那你們又能做什麼？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"나눠야 할 몫만 늘어나는 겁니다. 나눠야 할 몫만.","JPN":"それに各々の取り分が減るだけですよ、わかってます？","ENG":"If anything, it'll only increase the number of folks to split the spoils with. Meaning less for you.","TWN":"每個人能分到的東西只會更少而已，懂不懂。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"잘 생각해 보세요. 저 이터니움을.","JPN":"よく考えてみてください。あのエタニウムを。","ENG":"Think about it. Look at all that Eternium.","TWN":"好好想想吧，那些永恆之金。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"저걸 댁들끼리 나눠 가지면 용병 일에서 손 씻고 얼마든지 새로 시작할 수 있단 말입니다.","JPN":"あれをあなたたちだけで取り分ければ、傭兵の仕事なんかやめて新しい道を歩むことができるんですよ。","ENG":"If you split it among you, you could drop this mercenary work and get a brand new start.","TWN":"你們把那些永恆之金分了，從此金盆洗手，重新開始啊。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"그건 그렇지만......","JPN":"そりゃあそうだが……","ENG":"Sure, but...","TWN":"雖然是如此……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"자, 자. 더는 떠들 시간 없습니다.","JPN":"まあまあ、おしゃべりはこれくらいにしましょう。","ENG":"Come on, now. We can't afford any more chatter.","TWN":"好了，好了。沒時間在那跟你碎碎念了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"최대한 빨리 아티팩트와 이터니움을 안전한 곳으로 옮겨야 해요. 어떤 놈들이 냄새를 맡고 올지 모른단 말입니다.","JPN":"できるだけ早くアーティファクトとエタニウムを安全な場所に移さなければなりません。金のにおいを嗅ぎ付けた連中がいつ寄ってくるかわかりませんので。","ENG":"We've got to get the Artifacts and Eternium somewhere safe. There's no telling what sort of hyenas will sniff their way here.","TWN":"要快點把人造神器和永恆之金轉移到安全地帶。那些傢伙可能會聞著味道趕來呢。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"오, 윌버 군. 마침 잘 왔습니다.","JPN":"おお、ウィルバー君。ちょうどよかった。","ENG":"Oh, Wilbur. Perfect timing.","TWN":"哦，韋爾伯。來得正好。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"교...... 교수님?! 당신이 어떻게 여기......!","JPN":"きょ、教授！？　あなたがどうしてここに……！","ENG":"Prof... Professor?! How did you—","TWN":"教……教授？！您怎麼在這……！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"하하. 윌버 군 일행이 어디로 부상할지 예상하는 것쯤은 그리 어렵지 않아요.","JPN":"ハハハ。ウィルバー君たちがどこに浮上するか予想することくらい、簡単なことです。","ENG":"Hah hah. It wasn't so hard predicting where you'd be surfacing.","TWN":"哈哈。推測出你們一行人要躍出的位置並不是什麼難事。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};